App.tsx needs to be converted to use `WidgetProvider` + `WidgetRenderer` like this:
```tsx
import { WidgetProvider, useWidgets } from "./widgets/WidgetContext";
import { WidgetRenderer } from "./widgets/WidgetRenderer";

function Dashboard() {
  const { enabledKeys, entries, reorder, toggle, canMoveUp, canMoveDown, isEditing, toggleEdit } = useWidgets();
  return (
    <div className="app">
      <header className="app-header">
        <h1>Ops Dashboard</h1>
        <span className="meta">env: production</span>
        {isEditing && <button onClick={toggleEdit}>Done Editing</button>}
      </header>
      <div className="dashboard-grid">
        {entries.map((e, i) => (
          e.enabled ? (
            <WidgetRenderer
              key={e.key}
              widgetKey={e.key}
              draggable={isEditing}
              onRemove={isEditing ? () => toggle(e.key) : undefined}
              onReorder={isEditing ? (dir) => {
                const idx = dir === "up" ? i - 1 : i + 1;
                if (dir === "up" ? canMoveUp(i) : canMoveDown(i)) reorder(i, idx);
              } : undefined}
            />
          ) : null
        ))}
      </div>
    </div>
  );
}

export function App() {
  return (
    <WidgetProvider>
      <Dashboard />
    </WidgetProvider>
  );
}
```

